#include<bits/stdc++.h>
using namespace std;
long long dp[51][51][51][51],a[51][51];
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        for(long long j=1;j<=m;j++)
        {
            scanf("%lld",&a[i][j]);
        }
    }
    memset(dp,-0x3f,sizeof(dp));
    dp[1][1][1][1]=a[1][1];
    for(long long i=1;i<=n;i++)
    {
        for(long long j=1;j<=m;j++)
        {
            for(long long x=1;x<=n;x++)
            {
                for(long long y=1;y<=m;y++)
                {
                    if(i+j-1!=x+y-1)
                    {
                        continue;
                    }
                    if(i!=x||j!=y||(i==n&&j==m))
                    {
                        if(i>1&&x>1&&((i-1!=x-1||j!=y)||(i-1==1&&j==1)))
                        {
                            dp[i][j][x][y]=max(dp[i][j][x][y],dp[i-1][j][x-1][y]+a[i][j]+a[x][y]);
                        }
                        if(i>1&&y>1&&((i-1!=x||j!=y-1)||(i-1==1&&j==1)))
                        {
                            dp[i][j][x][y]=max(dp[i][j][x][y],dp[i-1][j][x][y-1]+a[i][j]+a[x][y]);
                        }
                        if(j>1&&x>1&&((i!=x-1||j-1!=y)||(i==1&&j-1==1)))
                        {
                            dp[i][j][x][y]=max(dp[i][j][x][y],dp[i][j-1][x-1][y]+a[i][j]+a[x][y]);
                        }
                        if(j>1&&y>1&&((i!=x||j-1!=y-1)||(i==1&&j-1==1)))
                        {
                            dp[i][j][x][y]=max(dp[i][j][x][y],dp[i][j-1][x][y-1]+a[i][j]+a[x][y]);
                        }
                    }
                }
            }
        }
    }
    printf("%lld",dp[n][m][n][m]);
    return 0;
}
